    IF Components.I2_iBuffer1IsReadyToLoad.IsTrue AND NOT _config.Buffer1Disabled THEN
        _requiredPosition := _positions.LoadFromBuffer1Pos;
        seq.StepCompleteWhen(TRUE);

    ELSIF Components.I4_iBuffer2IsReadyToLoad.Istrue AND NOT _config.Buffer2Disabled THEN
        _requiredPosition := _positions.LoadFromBuffer2Pos;
        seq.StepCompleteWhen(TRUE);

    ELSIF Components.I6_iBuffer3IsReadyToLoad.IsTrue AND NOT _config.Buffer3Disabled THEN
        _requiredPosition := _positions.LoadFromBuffer3Pos;
        seq.StepCompleteWhen(TRUE);

    ELSIF Components.I8_iBuffer4IsReadyToLoad.IsTrue AND NOT _config.Buffer4Disabled THEN
        _requiredPosition := _positions.LoadFromBuffer4Pos;
        seq.StepCompleteWhen(TRUE);
