            Messenger.Error('VSETKY ZASDOBNIKY SU VYPNUTE !!!

SEPAROVANIE VSTUPNEHO BLISTRA - ZASUNUTIE P10>') THEN   

    seq.StepCompleteWhen(Components.P10_HoldEntrySepareOutBlister.MoveToHome().Done  );
END_IF        
